SELECT *
FROM message_inbox
WHERE receiver_id = #{receiverId}
  AND is_broadcast = 0
  AND deleted = 0

    AND message_type = #{messageType}


    AND status = #{status}

ORDER BY create_time DESC

SELECT *
FROM message_inbox
WHERE sender_id = #{senderId}
  AND deleted = 0

    AND message_type = #{messageType}


    AND status = #{status}

ORDER BY create_time DESC
